INSERT INTO SY_ROLE (
    ROLE_NO, ROLE_ID, CPNY_ID, ORDERNO, ACTIVITY, SYS_TYPE,
    CREATE_DATE, CREATED_BY, UPDATE_DATE, UPDATED_BY
) VALUES (
    #{roleNo}, #{roleId}, #{cpnyId}, #{orderNo}, #{activity}, #{sysType},
    SYSDATE, #{adminID}, SYSDATE, #{adminID}
)

mapper.select:
SELECT r.*, (SELECT CONTENT FROM SY_GLOBAL_NAME WHERE NO = r.ROLE_NO AND LANGUAGE = 'vi') AS NAME_VI, (SELECT CONTENT FROM SY_GLOBAL_NAME WHERE NO = r.ROLE_NO AND LANGUAGE = 'en') AS NAME_EN, (SELECT CONTENT FROM SY_GLOBAL_NAME WHERE NO = r.ROLE_NO AND LANGUAGE = 'zh') AS NAME_ZH, (SELECT CONTENT FROM SY_GLOBAL_NAME WHERE NO = r.ROLE_NO AND LANGUAGE = 'ko') AS NAME_KO FROM SY_ROLE r WHERE r.CPNY_ID = #{cpnyId}
AND ( LOWER(r.ROLE_ID) LIKE LOWER('%' || #{keyword} || '%') OR LOWER(r.ROLE_NO) LIKE LOWER('%' || #{keyword} || '%') OR EXISTS ( SELECT 1 FROM SY_GLOBAL_NAME g WHERE g.NO = r.ROLE_NO AND LOWER(g.CONTENT) LIKE LOWER('%' || #{keyword} || '%') ) )
ORDER BY r.ORDERNO, r.ROLE_ID
